-- Aula 10: Variáveis e Tipos
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Validador de Tipos',
  'description', 'Crie uma função que retorna o tipo de uma variável.',
  'initialCode', '// Crie uma função que usa typeof para retornar o tipo\nfunction obterTipo(valor) {\n  // Seu código aqui\n}\n\nconsole.log(obterTipo(42));\nconsole.log(obterTipo("texto"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function obterTipo(valor) { return typeof valor; } console.log(obterTipo(42)); console.log(obterTipo("texto"));', 'expected', 'number\nstring')
  )
) WHERE id = 10;

-- Aula 11: Arrays e Objetos
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Manipular Array',
  'description', 'Crie uma função que adiciona um elemento ao final de um array.',
  'initialCode', '// Crie uma função que adiciona um item ao array\nfunction adicionarItem(array, item) {\n  // Seu código aqui\n  return array;\n}\n\nconst lista = [1, 2, 3];\nconsole.log(adicionarItem(lista, 4));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function adicionarItem(array, item) { array.push(item); return array; } const lista = [1, 2, 3]; console.log(adicionarItem(lista, 4));', 'expected', '1,2,3,4')
  )
) WHERE id = 11;

-- Aula 12: Funções e Escopo
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Calculadora Simples',
  'description', 'Crie uma função que soma dois números.',
  'initialCode', '// Crie uma função soma que recebe dois números\nfunction soma(a, b) {\n  // Seu código aqui\n}\n\nconsole.log(soma(5, 3));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function soma(a, b) { return a + b; } console.log(soma(5, 3));', 'expected', '8')
  )
) WHERE id = 12;

-- Aula 13: Componentes React
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Criar Componente',
  'description', 'Simule a criação de um componente React que retorna um título.',
  'initialCode', '// Crie uma função que retorna um objeto simulando JSX\nfunction Titulo(props) {\n  return { tag: "h1", texto: props.texto };\n}\n\nconsole.log(Titulo({ texto: "Olá React" }).texto);\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function Titulo(props) { return { tag: "h1", texto: props.texto }; } console.log(Titulo({ texto: "Olá React" }).texto);', 'expected', 'Olá React')
  )
) WHERE id = 13;

-- Aula 14: useState e Hooks
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Simular useState',
  'description', 'Crie uma função que simula o comportamento do useState.',
  'initialCode', '// Crie uma função que retorna um array com valor e função setter\nfunction useState(valorInicial) {\n  let valor = valorInicial;\n  const setValue = (novoValor) => { valor = novoValor; };\n  return [valor, setValue];\n}\n\nconst [count, setCount] = useState(0);\nconsole.log(count);\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function useState(valorInicial) { let valor = valorInicial; const setValue = (novoValor) => { valor = novoValor; }; return [valor, setValue]; } const [count, setCount] = useState(0); console.log(count);', 'expected', '0')
  )
) WHERE id = 14;

-- Aula 15: useEffect e Ciclo de Vida
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Simular useEffect',
  'description', 'Crie uma função que executa um efeito colateral.',
  'initialCode', '// Crie uma função que executa um callback\nfunction useEffect(callback) {\n  callback();\n}\n\nuseEffect(() => console.log("Efeito executado"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function useEffect(callback) { callback(); } useEffect(() => console.log("Efeito executado"));', 'expected', 'Efeito executado')
  )
) WHERE id = 15;

-- Aula 16: SQL Básico
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Gerar Query SELECT',
  'description', 'Crie uma função que gera uma query SQL SELECT.',
  'initialCode', '// Crie uma função que retorna "SELECT * FROM tabela"\nfunction gerarSelect(tabela) {\n  // Seu código aqui\n}\n\nconsole.log(gerarSelect("usuarios"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function gerarSelect(tabela) { return "SELECT * FROM " + tabela; } console.log(gerarSelect("usuarios"));', 'expected', 'SELECT * FROM usuarios')
  )
) WHERE id = 16;

-- Aula 17: Relacionamentos
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Criar JOIN',
  'description', 'Crie uma função que gera uma query com JOIN.',
  'initialCode', '// Crie uma função que retorna um JOIN entre duas tabelas\nfunction gerarJoin(tabela1, tabela2) {\n  return `SELECT * FROM ${tabela1} JOIN ${tabela2}`;\n}\n\nconsole.log(gerarJoin("users", "posts"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function gerarJoin(tabela1, tabela2) { return `SELECT * FROM ${tabela1} JOIN ${tabela2}`; } console.log(gerarJoin("users", "posts"));', 'expected', 'SELECT * FROM users JOIN posts')
  )
) WHERE id = 17;

-- Aula 18: Transações
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Simular Transação',
  'description', 'Crie funções que simulam BEGIN, COMMIT e ROLLBACK.',
  'initialCode', '// Crie funções que retornam os comandos SQL\nfunction begin() { return "BEGIN"; }\nfunction commit() { return "COMMIT"; }\n\nconsole.log(begin());\nconsole.log(commit());\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function begin() { return "BEGIN"; } function commit() { return "COMMIT"; } console.log(begin()); console.log(commit());', 'expected', 'BEGIN\nCOMMIT')
  )
) WHERE id = 18;

